values
( #{userData.compkey} , #{item.warekey} , FN_TM_VEHICKY() , #{item.vhcfnam} , #{item.vhcsnam} , #{item.dlvtype} , #{item.carrier} , #{item.vhcopty} , #{item.vhctype} , #{item.vhctncd} , #{item.maxwegt} , #{item.maxcapa} , #{item.sperfyn} , #{item.spelfyn} , #{item.specvyn} , #{item.spe04yn} , #{item.spe05yn} , #{item.vehgrnm} , #{item.vehcsnm} , #{item.vehtpyn} , #{item.inbvhyn} , #{item.oubvhyn} , #{item.gpseqyn} , #{item.gpsvhid} , #{item.imei}, #{item.msisdn} , #{item.vhrcsts}, #{item.vhcmemo}, #{item.vhuseyn} , #{item.mdestky} , #{item.ownernm} , to_char(now() , 'YYYYMMDD') , to_char(now() , 'hh24miss') , #{userData.useract}, to_char(now() , 'YYYYMMDD') , to_char(now() , 'hh24miss') , #{userData.useract} )

mapper.update:
/* updateVehicleList */

  update TVHCMA V
    set
      V.WAREKEY = #{item.warekey}
    , V.VHCFNAM = #{item.vhcfnam}
    , V.VHCSNAM = #{item.vhcsnam}
    , V.DLVTYPE = #{item.dlvtype}
    , V.CARRIER = #{item.carrier}
    , V.VHCOPTY = #{item.vhcopty}
    , V.VHCTYPE = #{item.vhctype}
    , V.VHCTNCD = #{item.vhctncd}
    , V.MAXWEGT = #{item.maxwegt}
    , V.MAXCAPA = #{item.maxcapa}
    , V.SPERFYN = #{item.sperfyn}
    , V.SPELFYN = #{item.spelfyn}
    , V.SPECVYN = #{item.specvyn}
    , V.SPE04YN = #{item.spe04yn}
    , V.SPE05YN = #{item.spe05yn}
    , V.VEHGRNM = #{item.vehgrnm}
    , V.VEHCSNM = #{item.vehcsnm}
    , V.VEHTPYN = #{item.vehtpyn}
    , V.INBVHYN = #{item.inbvhyn}
    , V.OUBVHYN = #{item.oubvhyn}
    , V.GPSEQYN = #{item.gpseqyn}
    , V.GPSVHID = #{item.gpsvhid}
    , V.IMEI = #{item.imei}
    , V.MSISDN = #{item.msisdn}
    , V.VHRCSTS = #{item.vhrcsts}
    , V.VHCMEMO = #{item.vhcmemo}
    , V.VHUSEYN = #{item.vhuseyn}
    , V.MDESTKY = #{item.mdestky}
    , V.OWNERNM = #{item.ownernm}

    , V.LMODATE = to_char(NOW(), 'YYYYMMDD')
    , V.LMOTIME = to_char(NOW(), 'hh24miss')
    , V.LMOUSER = #{userData.useract}

  where
    V.COMPKEY= #{item.compkey}
    and V.VEHICKY= #{item.vehicky}
    and V.WAREKEY= #{item.oldwarekey}

/* updateTpvassList */

  update TPVASS V
    set
      V.WAREKEY = #{item.warekey}
    , V.VAUMEMO = #{item.vaumemo}

    , V.VHUSEYN = #{item.vhuseyn}
    , V.VHOWNYN = #{item.vhownyn}

    , V.LMODATE = to_char(NOW(), 'YYYYMMDD')
    , V.LMOTIME = to_char(NOW(), 'hh24miss')
    , V.LMOUSER = #{userData.useract}

  where V.COMPKEY= #{item.compkey}
    and V.VEHICKY= #{item.vehicky}
    and V.USERACT= #{item.useract}

